export interface IChartCandlestickSlots extends IChartBaseSlots {
    /**
     * Replace the default tooltip card. Receives the usual `point` /
     * `series` / `category` bindings plus the full OHLC datum so the
     * custom slot can render change % and direction.
     */
    tooltip?: (bindings: {
        point: IChartPoint
        series: IChartBaseProps['series'][0]
        category: string | number
        datum: IChartCandlestickDatum
        change: number
        changePct: number
        isBullish: boolean
    }) => any
}

export interface IChartCartesianEmits extends IChartBaseEmits {
    /** Fired when the user drills into a sub-dataset. */
    (e: 'drill', link: IChartDrilldownLink, point: IChartPoint): void
    /** Fired when the user navigates back one drilldown level. */
    (e: 'drill-up'): void
    /**
     * Fired on every committed zoom (drag-release, wheel stop, or range-selector
     * button click). `start` and `end` are category indices (inclusive).
     */
    (e: 'zoom', range: { start: number, end: number }): void
    /** Fired when the user resets the zoom to the full data range. */
    (e: 'reset-zoom'): void
}

export interface IChartDrilldownDataset {
    /** Unique identifier — must match `IChartDrilldownLink.id` on the parent point. */
    id: string
    /** Human-readable name shown in the breadcrumb trail. */
    name: string
    /** Series rendered when this dataset is active. */
    series: Array<IChartSeries>
    /**
     * X-axis category labels for the sub-dataset. When absent the
     * chart falls back to numeric indices.
     */
    categories?: Array<string>
}

export interface IChartDrilldownFrame {
    /** Display name for this level (used in the breadcrumb). */
    name: string
    /** Series rendered at this level. */
    series: Array<IChartSeries>
    /** Category labels at this level. */
    categories: Array<string>
}

examples.code:
// IChartDrilldownFrame is an internal type used by the chart engine.
// It is rarely consumed directly. Reading it is useful when extending useChartDrilldown.
import type { IChartDrilldownFrame } from 'origam'

function rootFrame(series: IChartSeries[], categories: string[]): IChartDrilldownFrame {
    return { name: 'Root', series, categories }
}

