export interface IChartPlotBand {
    /**
     * Axis the band spans. `'y'` shades a horizontal stripe;
     * `'x'` shades a vertical stripe. Default `'y'`.
     */
    axis?: 'x' | 'y'
    /** Lower bound in axis units. String when `axis='x'` and categories are strings. */
    from: number | string
    /** Upper bound in axis units. */
    to: number | string
    /**
     * Fill colour. Accepts a `TIntent` token name or any CSS colour string.
     * Default resolves to the `warning` intent bg token.
     */
    color?: TIntent | string
    /** Fill opacity in the 0..1 range. Default `0.15`. */
    opacity?: number
    /** Optional label rendered centred inside the band. */
    label?: string
    /** Label fill colour. Accepts a `TIntent` token or CSS colour. Default `'currentColor'`. */
    labelColor?: TIntent | string
    /**
     * Z-order relative to chart data.
     * - `'below'` (default) — drawn behind series paths / bars / points.
     * - `'above'` — drawn on top of data.
     */
    layer?: 'below' | 'above'
}

export interface IChartPlotLine {
    /**
     * Axis the line is perpendicular to. `'y'` draws a horizontal
     * line at a Y value; `'x'` draws a vertical line at an X value.
     * Default `'y'`.
     */
    axis?: 'x' | 'y'
    /** Position on the axis in axis units. String when `axis='x'` and categories are strings. */
    value: number | string
    /**
     * Stroke colour. Accepts a `TIntent` token name or any CSS colour string.
     * Default resolves to the `danger` intent bg token.
     */
    color?: TIntent | string
    /** Stroke width in SVG user units. Default `1.5`. */
    width?: number
    /** Dash pattern of the line. Default `'dashed'`. */
    dash?: 'solid' | 'dashed' | 'dotted'
    /** Optional label placed at the end of the line. */
    label?: string
    /**
     * Horizontal alignment of the label for Y-axis lines.
     * `'right'` (default) places the label at the right edge;
     * `'left'` at the left edge.
     */
    labelAlign?: 'left' | 'right'
    /**
     * Z-order relative to chart data.
     * - `'below'` — drawn behind series.
     * - `'above'` (default) — drawn on top of data so the line remains visible.
     */
    layer?: 'below' | 'above'
}

